fixed_code:
struct MyString { inner: String }

impl MyString {
    fn new(s: String) -> Self { Self { inner: s } }
}

impl AsRef<str> for MyString {
    fn as_ref(&self) -> &str {
        self.inner.as_str()
    }
}

fn print_as_string<T: AsRef<str>>(t: T) {
    println!("{}", t.as_ref());
}

fn main() {
    let my_str = MyString::new(String::from("hello"));
    print_as_string(&my_str);
}
